export const GetSupplierOnboardingStatusResponse = zod
  .object({
    supplierId: zod.string().uuid(),
    stripeAccountId: zod.string().nullish(),
    stripeOnboardingStatus: zod.enum([
      "pending",
      "onboarding",
      "active",
      "suspended",
      "deauthorized",
    ]),
    chargesEnabled: zod
      .boolean()
      .describe(
        "Reserved — currently always false for V2 recipient-only accounts",
      ),
    payoutsEnabled: zod
      .boolean()
      .describe(
        'Derived from V2 stripe_transfers capability status === \"active\"',
      ),
    detailsSubmitted: zod
      .boolean()
      .describe("True when V2 requirements.currently_due is empty"),
    requirementsCurrentlyDue: zod
      .array(zod.string())
      .describe("V2 configuration.recipient.requirements.currently_due"),
    requirementsPastDue: zod
      .array(zod.string())
      .describe("V2 configuration.recipient.requirements.past_due"),
    capabilities: zod
      .unknown()
      .nullish()
      .describe(
        "Live snapshot of `account.configuration.recipient.capabilities`\nfrom V2 — used for inspection\/forensics; clients should prefer\nthe normalized booleans above for routine display.\n",
      ),
    fetchedAt: zod.coerce
      .date()
      .describe("When the live data was fetched (cache age = now - fetchedAt)"),
    cached: zod
      .boolean()
      .describe("True if returned from in-memory cache (≤60s old)"),
  })
  .describe(
    'Stripe V2 capabilities mapped to convenience booleans.\n\nStripe V2 does NOT expose top-level `charges_enabled` \/\n`payouts_enabled` booleans the way V1 did — those values must\nbe derived from `account.configuration.recipient.capabilities.\*`.\nThe mapping below is OUR normalization for admin UI convenience.\nThe full V2 capabilities object is also returned in `capabilities`\nfor inspection.\n\nMapping (V2 capability → boolean):\n  - `chargesEnabled`      ← (no direct V2 equivalent — Connect\n      accounts in V2 are recipient-only; this stays `false` for\n      transfer-only accounts and is reserved for future use if\n      we add merchant capabilities)\n  - `payoutsEnabled`      ← `configuration.recipient.capabilities\n      .stripe_balance.stripe_transfers.status === \"active\"`\n      i.e. the supplier can receive transfers from our platform\n      balance into their Stripe balance and have them paid out.\n  - `detailsSubmitted`    ← `configuration.recipient.requirements\n      .currently_due` is empty (i.e. Stripe has no outstanding\n      asks blocking onboarding). `eventually_due` items do NOT\n      block — they are future requirements (e.g. when the supplier\n      crosses a transaction-volume threshold) and are surfaced\n      separately to admins via the raw `capabilities` blob.\n      This formula is the canonical definition for both this\n      field and any server-side gating logic.\n',
  );

